// Format decay alerts for Slack
const data = $input.first().json.body || $input.first().json;
const alerts = data.alerts || [];

const critical = alerts.filter(a => a.severity === 'critical');
const warning = alerts.filter(a => a.severity === 'warning');
const info = alerts.filter(a => a.severity === 'info');

let message = `:chart_with_downwards_trend: *Content Decay Alert*\n`;
message += `*Summary:* ${data.summary}\n\n`;

if (critical.length > 0) {
  message += `:rotating_light: *Critical (>50% decline):*\n`;
  critical.slice(0, 5).forEach(a => {
    message += `• ${a.message}\n`;
  });
  if (critical.length > 5) message += `_...and ${critical.length - 5} more_\n`;
  message += `\n`;
}

if (warning.length > 0) {
  message += `:warning: *Warning (30-50% decline):*\n`;
  warning.slice(0, 5).forEach(a => {
    message += `• ${a.message}\n`;
  });
  if (warning.length > 5) message += `_...and ${warning.length - 5} more_\n`;
  message += `\n`;
}

if (info.length > 0) {
  message += `:information_source: *Info (20-30% decline):*\n`;
  info.slice(0, 3).forEach(a => {
    message += `• ${a.message}\n`;
  });
  if (info.length > 3) message += `_...and ${info.length - 3} more_\n`;
}

return [{ json: { slack_message: message, alert_count: alerts.length } }];
